import app.k9mail.legacy.account.Account
import app.k9mail.legacy.account.AccountManager
import com.fsck.k9.K9
import com.fsck.k9.Preferences
import org.junit.After
import org.junit.Assert.assertFalse
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test
import org.mockito.kotlin.mock
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever

class UnifiedInboxConfiguratorTest {
    private val accountManager = mock<AccountManager>()
    private val preferences = mock<Preferences>()
    private val storageEditor = mock<StorageEditor>()

    private lateinit var configurator: UnifiedInboxConfigurator

    @Before
    fun setUp() {
        configurator = UnifiedInboxConfigurator(accountManager, preferences)
        whenever(preferences.createStorageEditor()).thenReturn(storageEditor)
        // Reset K9.isShowUnifiedInbox to default state
        K9.isShowUnifiedInbox = false
    }

    @After
    fun tearDown() {
        // Reset to default state
        K9.isShowUnifiedInbox = false
    }

    @Test
    fun `configureUnifiedInbox should not enable unified inbox when there is only one account`() {
        val account = mock<Account>()
        whenever(accountManager.getAccounts()).thenReturn(listOf(account))

        configurator.configureUnifiedInbox()

        assertFalse(K9.isShowUnifiedInbox)
    }

    @Test
    fun `configureUnifiedInbox should enable unified inbox when there are two accounts`() {
        val account1 = mock<Account>()
        val account2 = mock<Account>()
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2))

        configurator.configureUnifiedInbox()

        assertTrue(K9.isShowUnifiedInbox)
        verify(storageEditor).commit()
    }

    @Test
    fun `configureUnifiedInbox should enable unified inbox when there are three accounts`() {
        val account1 = mock<Account>()
        val account2 = mock<Account>()
        val account3 = mock<Account>()
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2, account3))

        configurator.configureUnifiedInbox()

        assertTrue(K9.isShowUnifiedInbox)
        verify(storageEditor).commit()
    }

    @Test
    fun `configureUnifiedInbox should not change unified inbox when it is already enabled`() {
        val account1 = mock<Account>()
        val account2 = mock<Account>()
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2))
        K9.isShowUnifiedInbox = true

        configurator.configureUnifiedInbox()

        assertTrue(K9.isShowUnifiedInbox)
        // Verify that settings are not saved unnecessarily
        verify(preferences, org.mockito.kotlin.never()).createStorageEditor()
    }

    @Test
    fun `configureUnifiedInbox should save settings synchronously`() {
        val account1 = mock<Account>()
        val account2 = mock<Account>()
        whenever(accountManager.getAccounts()).thenReturn(listOf(account1, account2))

        configurator.configureUnifiedInbox()

        // Verify that settings are saved synchronously (commit is called, not just prepared)
        verify(preferences).createStorageEditor()
        verify(storageEditor).commit()
    }
}
